parameters.jsCode:
// Extract a stable failure record from n8n's error-trigger payload.
const e = $json ?? {};
const execution = e.execution ?? {};
const workflow = e.workflow ?? {};
const err = execution.error ?? e.trigger?.error ?? {};

return [{ json: {
  failed_workflow: workflow.name ?? 'unknown workflow',
  failed_workflow_id: workflow.id ?? null,
  execution_id: execution.id ?? null,
  execution_url: execution.url ?? null,
  failed_node: execution.lastNodeExecuted ?? err.node?.name ?? 'unknown node',
  error_message: String(err.message ?? 'no message').slice(0, 500),
  error_description: String(err.description ?? '').slice(0, 500),
  mode: execution.mode ?? null,
  retry_of: execution.retryOf ?? null,
  ts: new Date().toISOString(),
} }];

// The error handler must never depend on the LLM working — the hint is a
// bonus, the alert goes out either way.
const ctx = $('Extract Failure Context').item.json;
let hint = $json.message?.content ?? $json.output ?? null;
if (typeof hint === 'string') {
  try { hint = JSON.parse((hint.match(/\{[\s\S]*\}/) || ['null'])[0]); } catch (e) { hint = null; }
}
return { json: {
  ...ctx,
  likely_cause: hint?.likely_cause ?? null,
  first_step: hint?.first_step ?? null,
} };

